def _run_version_command(cmd: list[str]) -> str | None:
    """Run a version command and return the most likely package x.y.z version found."""
    try:
        result = subprocess.run(
            cmd,
            capture_output=True,
            text=True,
            timeout=10,
        )
    except Exception:
        return None

    candidates: list[str] = []
    combined = result.stdout.splitlines() + result.stderr.splitlines()
    for line in combined:
        line = line.strip()
        if not line:
            continue
        matches = _re.findall(r"(\d+\.\d+\.\d+)", line)
        if matches:
            candidates.extend(matches)

    if not candidates:
        return None

    filtered = [v for v in candidates if v != "0.0.0"]
    if filtered:
        candidates = filtered

    preferred = [v for v in candidates if v.startswith("3.")]
    if preferred:
        candidates = preferred

    return candidates[-1]


